-- Insert 47 mobility exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min::int,
  d.sets::int, d.reps::int, d.work::int, d.rest::int, d.est::int,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Walking Knee Hug to Calf Raise', 'walking-knee-hug-to-calf-raise', 'Walk forward, pull one knee toward the chest, rise into a controlled calf raise on the stance leg, then step through into the next rep.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens hip flexion, glute length, foot tripod, and ankle stiffness. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Gait mobility', 'prepare_and_access', 'mobilize', 'gait_hip_flexion_ankle_prep', '{"primary_joint_actions":["hip_flexion","ankle_plantarflexion","single_leg_posture_control"],"primary_tissues":["glutes","hip_capsule","calves","intrinsic_foot_muscles"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"moderate single-leg or shifting support","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Walk forward, pull one knee toward the chest, rise into a controlled calf raise on the stance leg, then step through into the next rep.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward hip flexion, glute length, foot tripod, and ankle stiffness, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Walking Quad Pull with Overhead Reach', 'walking-quad-pull-with-overhead-reach', 'Walk forward, catch one foot behind the body, gently pull the heel toward the glute, reach the opposite arm overhead, then step through.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens front-of-hip length, quad length, tall posture, and shoulder reach. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Gait mobility', 'prepare_and_access', 'mobilize', 'gait_hip_extension_prep', '{"primary_joint_actions":["knee_flexion","hip_extension","shoulder_flexion","trunk_stack_control"],"primary_tissues":["quadriceps","rectus_femoris","hip_flexors","lat_fascia"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"moderate single-leg or shifting support","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Walk forward, catch one foot behind the body, gently pull the heel toward the glute, reach the opposite arm overhead, then step through.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward front-of-hip length, quad length, tall posture, and shoulder reach, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Open Gate / Close Gate Walk', 'open-gate-close-gate-walk', 'Walk forward while lifting one knee, circling the hip outward or inward, and stepping down softly with the pelvis level.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens hip rotation during stepping, pelvis control, and gait rhythm. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Hip circle gait mobility', 'prepare_and_access', 'mobilize', 'gait_hip_rotation_prep', '{"primary_joint_actions":["hip_flexion","hip_external_rotation","hip_internal_rotation","pelvic_control"],"primary_tissues":["hip_rotators","adductors","glutes","hip_capsule"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Walk forward while lifting one knee, circling the hip outward or inward, and stepping down softly with the pelvis level.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward hip rotation during stepping, pelvis control, and gait rhythm, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Dynamic Leg Swing Front-to-Back', 'dynamic-leg-swing-front-to-back', 'Hold light support and swing one leg forward and backward like a pendulum while the ribs and pelvis stay quiet.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens active hip flexion and extension without trunk compensation. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Swing mobility', 'prepare_and_access', 'mobilize', 'sagittal_leg_swing_prep', '{"primary_joint_actions":["hip_flexion","hip_extension","pelvic_stack_control"],"primary_tissues":["hamstrings","hip_flexors","glutes","calves"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"moderate single-leg or shifting support","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Hold light support and swing one leg forward and backward like a pendulum while the ribs and pelvis stay quiet.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward active hip flexion and extension without trunk compensation, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Dynamic Leg Swing Lateral', 'dynamic-leg-swing-lateral', 'Hold light support and swing one leg across the body and out to the side while the standing foot stays grounded and the trunk stays tall.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens adductor length, lateral hip access, and pelvis control. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Swing mobility', 'prepare_and_access', 'mobilize', 'frontal_leg_swing_prep', '{"primary_joint_actions":["hip_abduction","hip_adduction","pelvic_control","ankle_balance"],"primary_tissues":["adductors","glute_med","lateral_hip","hip_capsule"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"moderate single-leg or shifting support","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Hold light support and swing one leg across the body and out to the side while the standing foot stays grounded and the trunk stays tall.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward adductor length, lateral hip access, and pelvis control, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Ankle Knee-to-Wall Rocker', 'ankle-knee-to-wall-rocker', 'Place the foot near a wall and rock the knee toward the wall over the middle toes while the heel stays heavy and the arch stays organized.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens ankle dorsiflexion, heel contact, and knee-over-foot tracking. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Ankle dorsiflexion mobility', 'prepare_and_access', 'mobilize', 'foot_ankle_mobility', '{"primary_joint_actions":["ankle_dorsiflexion","knee_flexion","foot_tripod_control"],"primary_tissues":["soleus","gastrocnemius","achilles_tendon","ankle_capsule"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Place the foot near a wall and rock the knee toward the wall over the middle toes while the heel stays heavy and the arch stays organized.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward ankle dorsiflexion, heel contact, and knee-over-foot tracking, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Down Dog Calf Pedal', 'down-dog-calf-pedal', 'From a down-dog position, alternate bending one knee and pressing the opposite heel toward the floor with smooth breathing.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens calf length, hamstring tone, and shoulder-supported hip hinge. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Posterior-chain mobility', 'prepare_and_access', 'mobilize', 'posterior_chain_mobility', '{"primary_joint_actions":["ankle_dorsiflexion","knee_extension","hip_flexion","shoulder_flexion"],"primary_tissues":["gastrocnemius","soleus","hamstrings","plantar_fascia"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"From a down-dog position, alternate bending one knee and pressing the opposite heel toward the floor with smooth breathing.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward calf length, hamstring tone, and shoulder-supported hip hinge, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Short Foot to Calf Raise Mobility Prep', 'short-foot-to-calf-raise-mobility-prep', 'Create a gentle arch without curling the toes, then rise into a slow calf raise while keeping the tripod foot and tall posture.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens foot tripod, arch control, and controlled ankle plantarflexion. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Foot and ankle control', 'prepare_and_access', 'mobilize', 'foot_ankle_mobility', '{"primary_joint_actions":["intrinsic_foot_activation","ankle_plantarflexion","toe_extension_control"],"primary_tissues":["intrinsic_foot_muscles","plantar_fascia","calves","achilles_tendon"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"Create a gentle arch without curling the toes, then rise into a slow calf raise while keeping the tripod foot and tall posture.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward foot tripod, arch control, and controlled ankle plantarflexion, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('A-March Mobility with Arm Sweep', 'a-march-mobility-with-arm-sweep', 'March forward with controlled knee lift while sweeping the opposite arm through a relaxed sprint arm path and staying tall through the crown of the head.', 'BEGINNER', 8, 1, 6, 45, 0, 45, 'Dynamic mobility drill that opens hip flexion rhythm, ankle position, posture, and opposite-arm swing. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Sprint mobility rhythm', 'prepare_and_access', 'mobilize', 'gait_mobility_flow', '{"primary_joint_actions":["hip_flexion","ankle_dorsiflexion","shoulder_flexion_extension","contralateral_coordination"],"primary_tissues":["hip_flexors","calves","anterior_tibialis","shoulder_complex"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"low to moderate","impact_level":0}'::jsonb, '{"movement_description":"March forward with controlled knee lift while sweeping the opposite arm through a relaxed sprint arm path and staying tall through the crown of the head.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward hip flexion rhythm, ankle position, posture, and opposite-arm swing, not toward maximum speed or fatigue."],"execution_ste