  ('Gorilla Squat Lateral Shift', 'gorilla-squat-lateral-shift', 'From a low squat or hinge, plant the hands lightly, shift the hips side to side, and step or rock laterally without collapsing posture.', 'BEGINNER', 8, 2, 5, 60, 15, 75, 'Dynamic mobility drill that opens deep squat access, lateral hip shift, ankle mobility, and trunk control. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Low squat locomotion mobility', 'prepare_and_access', 'mobilize', 'global_mobility_flow', '{"primary_joint_actions":["deep_squat","lateral_hip_shift","ankle_dorsiflexion","hand_support"],"primary_tissues":["adductors","glutes","calves","wrists"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"From a low squat or hinge, plant the hands lightly, shift the hips side to side, and step or rock laterally without collapsing posture.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward deep squat access, lateral hip shift, ankle mobility, and trunk control, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Kang Squat Mobility Flow', 'kang-squat-mobility-flow', 'Move from a tall stance to a hip hinge, drop into a squat while keeping a long spine, then stand with control.', 'BEGINNER', 8, 2, 5, 60, 15, 75, 'Dynamic mobility drill that opens hamstrings, hips, squat depth, and torso control through hinge-to-squat transitions. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Squat-hinge mobility flow', 'prepare_and_access', 'mobilize', 'squat_hinge_mobility_flow', '{"primary_joint_actions":["hip_hinge","deep_squat","knee_flexion","spine_position_control"],"primary_tissues":["hamstrings","adductors","glutes","spinal_erectors"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Move from a tall stance to a hip hinge, drop into a squat while keeping a long spine, then stand with control.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward hamstrings, hips, squat depth, and torso control through hinge-to-squat transitions, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb),
  ('Traveling Ape Reach', 'traveling-ape-reach', 'From a low squat or crouch, place the hands to one side, shift weight through the arms, and step the feet across with a controlled reach.', 'BEGINNER', 8, 2, 5, 60, 15, 75, 'Dynamic mobility drill that opens lateral hip mobility, shoulder support, trunk rotation, and playful athletic rhythm. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Animal locomotion mobility', 'prepare_and_access', 'mobilize', 'locomotion_mobility_flow', '{"primary_joint_actions":["lateral_locomotion","shoulder_weight_bearing","hip_abduction","trunk_rotation"],"primary_tissues":["adductors","glutes","serratus_anterior","wrists","obliques"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"From a low squat or crouch, place the hands to one side, shift weight through the arms, and step the feet across with a controlled reach.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward lateral hip mobility, shoulder support, trunk rotation, and playful athletic rhythm, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position