  ('Ground-to-Stand Mobility Flow', 'ground-to-stand-mobility-flow', 'Move from the floor through a shin box or lunge transition to standing, then reverse the path with control and smooth breathing.', 'BEGINNER', 8, 2, 5, 60, 15, 75, 'Dynamic mobility drill that opens hip rotation, trunk control, shoulder support, and athletic transition ability. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.', 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.', 'Move smoothly, breathe through the range, and own the position you create.', 'Whole-body transition mobility', 'prepare_and_access', 'mobilize', 'global_mobility_flow', '{"primary_joint_actions":["ground_to_stand_transition","hip_rotation","lunge_transition","trunk_bracing"],"primary_tissues":["hip_rotators","glutes","adductors","shoulder_stabilizers","deep_core"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"moderate","impact_level":0}'::jsonb, '{"movement_description":"Move from the floor through a shin box or lunge transition to standing, then reverse the path with control and smooth breathing.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward hip rotation, trunk control, shoulder support, and athletic transition ability, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."]}'::jsonb)
) AS d(name, slug, description, skill, age_min, sets, reps, work, rest, est, summary, coach_lang, athlete_lang, family, phase_key, subrole, slot, req, exec)
